VALUES
  ('social-worker-moex-03136', 'social-worker', 'social-worker-moex-100-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關唐氏症兒童的描述，下列何者錯誤？', '["唐氏症是一種症候群，與染色體異常無關", "唐氏症兒童生長較為遲緩、壽命比正常人短，主要的問題是智能障礙", "唐氏症兒童常會伴隨先天性心臟病、先天性腸胃道畸形、視力、聽力缺損等", "唐氏症的發生率與母親生育的年齡有相當大的關係"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "e30518f435ea", "answer_pdf_sha1": "d92305120445", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03137', 'social-worker', 'social-worker-moex-100-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '由人文學派Thomas Gordon所創的父母效能訓練（PET）處遇策略中，下列那一項是正確的描述？', '["父母需要多用威權才能從小把孩子管教好", "父母應強調一致性的管教原則，才不會造成親子衝突", "父母應多使用「我的訊息」和孩子進行表達和溝通", "父母只需重視孩子的行為結果給予獎賞，不需重視其想法和動機"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "e30518f435ea", "answer_pdf_sha1": "d92305120445", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03138', 'social-worker', 'social-worker-moex-100-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列那一項對懷孕期的描述錯誤？', '["懷孕婦女的情緒反應並不會透過胎盤影響胎兒的發展", "懷孕期間吸菸婦女的胎兒出生體重比不吸菸婦女的胎兒來得輕", "貧窮是影響胎兒生存的心理和社會因素", "從受孕的那一刻開始，父母親的基因就影響胎兒的發展"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "e30518f435ea", "answer_pdf_sha1": "d92305120445", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03139', 'social-worker', 'social-worker-moex-100-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '嬰兒的發展是有目的性的動作發展，具有發展的原則，下列那一項是正確的發展原則？', '["從頭到尾的發展原則，又稱頭尾定律", "從複雜到簡單的發展模式", "從小肌肉到大肌肉的發展原則", "由遠至近的動作發展原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "e30518f435ea", "answer_pdf_sha1": "d92305120445", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03140', 'social-worker', 'social-worker-moex-100-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列有關婦女產後憂鬱症的敘述何者錯誤？', '["產生原因與荷爾蒙失調或過度疲勞有關", "一般症狀會在幾天或幾週內消失", "有時症狀會持續幾個月", "一般症狀是在生產後8週內出現"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "e30518f435ea", "answer_pdf_sha1": "d92305120445", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03141', 'social-worker', 'social-worker-moex-100-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列對注意力缺損過動症（ADHD）的描述，何者錯誤？', '["ADHD是指兒童在發展過程中的注意力缺損，進入青少年期症狀就會消失", "社會工作者對ADHD的服務角色需扮演仲介者角色，協助連結資源", "ADHD兒童的治療方法有遊戲治療、家族治療、藥物治療法等方法", "ADHD並非單純是因為孩子天生的個性或周遭環境所引起的"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "e30518f435ea", "answer_pdf_sha1": "d92305120445", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03142', 'social-worker', 'social-worker-moex-100-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列有關造成兒童虐待的環境因素，那一項的敘述最正確？', '["貧窮、婚姻衝突、社會孤立、缺乏社會支持", "貧窮、社會孤立、照顧者使用藥物、社區暴力", "貧窮、酒癮、兒童失能、社區暴力", "貧窮、失業、社會孤立、缺乏社會支持"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "e30518f435ea", "answer_pdf_sha1": "d92305120445", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03143', 'social-worker', 'social-worker-moex-100-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '在兒童虐待常見的形式中，所謂兒童疏忽的行為模式為何？', '["毆打或體罰", "生活需求供應不足", "不當的觸摸", "經常不讓兒童去上課"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "e30518f435ea", "answer_pdf_sha1": "d92305120445", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03144', 'social-worker', 'social-worker-moex-100-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '在兒童時期，憂鬱症患者所顯現的行為方式，下列敘述何者正確？', '["注意力不集中", "拒絕上學，對活動無興趣", "上課不專心，嗜睡", "拒絕飲食或食量偏低"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "e30518f435ea", "answer_pdf_sha1": "d92305120445", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03145', 'social-worker', 'social-worker-moex-100-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '為了有效降低兒童的攻擊行為，下列的處理方式那一種是最適當的？', '["不予理會、暫時隔離、楷模角色學習、提供無暴力環境", "不予理會、適當懲罰、暫時隔離、楷模角色學習", "不予理會、積極勸說、提供無暴力環境、暫時隔離", "不予理會、訂定行為規範、楷模角色學習、建立無暴力環境"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "e30518f435ea", "answer_pdf_sha1": "d92305120445", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03146', 'social-worker', 'social-worker-moex-100-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '最近三年（民國97-99年）國人十大死亡原因排名前三項的病症為何？', '["癌症、心臟病、肝病", "癌症、高血壓、糖尿病", "癌症、心臟病、腦血管疾病", "癌症、肺炎、心臟病"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "e30518f435ea", "answer_pdf_sha1": "d92305120445", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03147', 'social-worker', 'social-worker-moex-100-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列描述何者正確？', '["認為強暴生存者本身應受到指責的觀點是屬於女性主義的觀點", "性侵害犯罪之案件，審判需公開，以讓法官或軍事審判官更了解案情", "工作人員於執行勤務知有性侵犯罪情事者，至遲必須在48小時通報當地主管機關", "預防強暴方法中，大叫「失火了」或「警察」通常會比大叫「救命」或「強暴」來得好"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "e30518f435ea", "answer_pdf_sha1": "d92305120445", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03148', 'social-worker', 'social-worker-moex-100-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '所謂「功能性文盲」（functionally illiterate）的界定是指：', '["不能看懂文字涵義的人", "看不懂文字，卻可以藉聽力了解涵義的人", "具有閱讀的能力，但無法適應社會需求的人", "暫時性對文字失去使用能力的人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "e30518f435ea", "answer_pdf_sha1": "d92305120445", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03149', 'social-worker', 'social-worker-moex-100-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '依據Erickson 的觀點，成人中期若面臨停滯現象，其表現出來的行為模式不包含下列那一項？', '["無法適應生活挑戰", "只能滿足自我，無法兼顧別人的需求", "花盡所有累積的財富", "感覺自己的能力有限，資源不足"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "e30518f435ea", "answer_pdf_sha1": "d92305120445", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
